    {
      "name": "header_menu_z_index",
      "input": {
        "screen_elements": ["header", "content"],
        "z_index_header": 100,
        "z_index_content": 50
      },
      "output": "header should overlay content",
      "args": [],
      "kwargs": {},
      "notes": "Checks if the header menu overlays other elements based on z-index."
    },
    {
      "name": "responsive_design",
      "input": {
        "viewport_size": "mobile",
        "screen_elements": ["header", "content"]
      },
      "output": "header should adapt to mobile view",
      "args": [],
      "kwargs": {},
      "notes": "Validates that the header menu is responsive on mobile devices."
    },
    {
      "name": "header_menu_interaction",
      "input": {
        "screen_elements": ["header", "dropdown"],
        "dropdown_visible": false
      },
      "output": "dropdown should appear on header click",
      "args": [],
      "kwargs": {},
      "notes": "Ensures that the dropdown menu appears when the header is clicked."
    },
    {
      "name": "header_menu_scroll_behavior",
      "input": {
        "scroll_position": "down",
        "header_position": "fixed"
      },
      "output": "header should remain fixed",
      "args": [],
      "kwargs": {},
      "notes": "Tests if the header remains fixed during scrolling."
    },
    {
      "name": "header_menu_edge_case_1",
      "input": {
        "screen_elements": ["header", "content"],
        "z_index_header": 0,
        "z_index_content": 100
      },
      "output": "header should be behind content",
      "args": [],
      "kwargs": {},
      "notes": "Tests an edge case where the header has a lower z-index than content."
    },
    {
      "name": "header_menu_edge_case_2",
      "input": {
        "screen_elements": ["header", "modal"],
        "modal_visible": true
      },
      "output": "header should be hidden behind modal",
      "args": [],
      "kwargs": {},
      "notes": "Checks if the header is hidden when a modal is displayed."
    },
    {
      "name": "header_menu_no_elements",
      "input": {
        "screen_elements": []
      },
      "output": "no header to display",
      "args": [],
      "kwargs": {},
      "notes": "Validates behavior when there are no screen elements."
    }
  ],
  "assumptions": "The header menu is expected to be a fixed element on the page.",
  "notes": "Ensure to test across different browsers for compatibility."
